const now = new Date();
const lookbackHours = parseInt($.input.lookbackHours || '24', 10);
const lookbackDate = new Date(now.getTime() - lookbackHours * 3600000);

const calStart = new Date(now);
calStart.setHours(0, 0, 0, 0);
const calEnd = new Date(now);
calEnd.setDate(calEnd.getDate() + 5);
calEnd.setHours(23, 59, 59, 999);

const afterDate = lookbackDate.toISOString().split('T')[0].replace(/-/g, '/');

return {
  gmailQuery: 'is:unread newer_than:' + lookbackHours + 'h',
  calTimeMin: calStart.toISOString(),
  calTimeMax: calEnd.toISOString(),
  today: now.toISOString().split('T')[0],
  nowISO: now.toISOString()
};

const iterations = ($.steps.fetchEmailDetails && $.steps.fetchEmailDetails.response && $.steps.fetchEmailDetails.response.iterations) || [];

const emails = [];
iterations.forEach((iter, i) => {
  const resp = (iter.getEmail && iter.getEmail.response) ? iter.getEmail.response : null;
  if (!resp) return;

  const headers = resp.payload && resp.payload.headers ? resp.payload.headers : [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };

  let body = '';
  if (resp.payload && resp.payload.body && resp.payload.body.data) {
    try { body = Buffer.from(resp.payload.body.data, 'base64').toString('utf-8'); } catch(e) { body = ''; }
  } else if (resp.payload && resp.payload.parts) {
    const textPart = resp.payload.parts.find(p => p.mimeType === 'text/plain');
    if (textPart && textPart.body && textPart.body.data) {
      try { body = Buffer.from(textPart.body.data, 'base64').toString('utf-8'); } catch(e) { body = ''; }
    }
  }
  if (!body) body = resp.snippet || '';

  emails.push({
    id: resp.id,
    threadId: resp.threadId,
    from: getHeader('From'),
    subject: getHeader('Subject'),
    date: getHeader('Date'),
    body: body.slice(0, 1500),
    snippet: resp.snippet || ''
  });
});

return { emails, emailCount: emails.length };

const events = $.steps.listCalendarEvents.response.items || [];
const workStart = parseInt($.input.workingHoursStart || '9', 10);
const workEnd = parseInt($.input.workingHoursEnd || '17', 10);

let calText = 'EXISTING CALENDAR EVENTS (next 5 days):\n\n';
const busySlots = [];

events.forEach(e => {
  const start = e.start.dateTime || e.start.date;
  const end = e.end.dateTime || e.end.date;
  const startDate = new Date(start);
  const endDate = new Date(end);
  const dayStr = startDate.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
  const startTime = startDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
  const endTime = endDate.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
  calText += '- ' + dayStr + ': ' + (e.summary || '(busy)') + ' ' + startTime + ' - ' + endTime + '\n';
  busySlots.push({ start: startDate.toISOString(), end: endDate.toISOString() });
});

calText += '\nWORKING HOURS: ' + workStart + ':00 - ' + workEnd + ':00\n';
calText += 'BUSY SLOTS: ' + busySlots.length + ' events\n';

return { calText, busySlots, eventCount: events.length, workStart, workEnd };

const emails = $.steps.parseEmails.output.emails;
const calData = $.steps.formatCalendar.output;
const duration = $.input.meetingDuration || '30';
const today = $.steps.getDateBounds.output.today;

let emailText = 'RECENT EMAILS:\n\n';
emails.forEach((e, i) => {
  emailText += '--- EMAIL ' + (i + 1) + ' ---\n';
  emailText += 'From: ' + e.from + '\n';
  emailText += 'Subject: ' + e.subject + '\n';
  emailText += 'Date: ' + e.date + '\n';
  emailText += 'Body:\n' + e.body + '\n\n';
});

let prompt = 'You are an executive scheduling assistant. Analyze the recent emails below to identify any meeting requests or scheduling inquiries. Then check the calendar availability and suggest appropriate time slots.\n\n';
prompt += 'TODAY: ' + today + '\n';
prompt += 'DEFAULT MEETING DURATION: ' + duration + ' minutes\n\n';
prompt += emailText + '\n';
prompt += calData.calText + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify which emails are requesting meetings or appointments\n';
prompt += '- For each meeting request, suggest 3 available time slots that do not conflict with existing events\n';
prompt += '- Only suggest slots within working hours\n';
prompt += '- Draft a professional reply email for each meeting request\n';
prompt += '- If an email is NOT a meeting request, mark it as such\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "meetingRequests": [\n';
prompt += '    {\n';
prompt += '      "emailIndex": 1,\n';
prompt += '      "from": "sender email",\n';
prompt += '      "subject": "email subject",\n';
prompt += '      "isMeetingRequest": true,\n';
prompt += '      "meetingTopic": "inferred meeting topic",\n';
prompt += '      "suggestedSlots": [\n';
prompt += '        { "date": "YYYY-MM-DD", "startTime": "HH:MM", "endTime": "HH:MM", "display": "human-readable slot" }\n';
prompt += '      ],\n';
prompt += '      "replyDraft": "professional reply email text suggesting the time slots",\n';
prompt += '      "replySubject": "Re: original subject"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "summary": "brief summary of findings",\n';
prompt += '  "totalMeetingRequests": 0\n';
prompt += '}';

return { prompt, emailCount: emails.length };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { meetingRequests: [], summary: raw, totalMeetingRequests: 0 }; }

const ai = $.steps.parseAI.output;
const emails = $.steps.parseEmails.output.emails;
const senderName = $.input.senderName || 'AI Assistant';

const meetingRequests = (ai.meetingRequests || []).filter(r => r.isMeetingRequest);

const replies = meetingRequests.map(req => {
  const emailIdx = req.emailIndex - 1;
  const originalEmail = emails[emailIdx] || {};

  let fromEmail = originalEmail.from || '';
  const emailMatch = fromEmail.match(/<([^>]+)>/);
  if (emailMatch) fromEmail = emailMatch[1];
  else fromEmail = fromEmail.trim();

  let replyBody = (req.replyDraft || '').trim();
  if (!replyBody.includes(senderName)) {
    replyBody += '\n\nBest regards,\n' + senderName;
  }

  return {
    to: fromEmail,
    subject: req.replySubject || ('Re: ' + (originalEmail.subject || 'Meeting Request')),
    body: replyBody,
    threadId: originalEmail.threadId || null,
    messageId: originalEmail.id || null,
    meetingTopic: req.meetingTopic || '',
    suggestedSlots: req.suggestedSlots || []
  };
}).filter(r => r.to && r.to.includes('@'));

return { replies, replyCount: replies.length, summary: ai.summary || '' };
